727	func removeIgnDuplicateFilesUnitsUsers(ignConfig ign2types.Config) (ign2types.Config, error) {
728	
729		files := ignConfig.Storage.Files
730		units := ignConfig.Systemd.Units
731		users := ignConfig.Passwd.Users
732	
733		filePathMap := map[string]bool{}
734		var outFiles []ign2types.File
735		for i := len(files) - 1; i >= 0; i-- {
736			// We do not actually support to other filesystems so we make the assumption that there is only 1 here
737			path := files[i].Path
738			if _, isDup := filePathMap[path]; isDup {
739				continue
740			}
741			outFiles = append(outFiles, files[i])
742			filePathMap[path] = true
743		}
744	
745		unitNameMap := map[string]bool{}
746		var outUnits []ign2types.Unit
747		for i := len(units) - 1; i >= 0; i-- {
748			unitName := units[i].Name
749			if _, isDup := unitNameMap[unitName]; isDup {
750				// this is a duplicated unit by name, so let's check for the dropins and append them
751				if len(units[i].Dropins) > 0 {
752					for j := range outUnits {
753						if outUnits[j].Name == unitName {
754							// outUnits[j] is the highest priority entry with this unit name
755							// now loop over the new unit's dropins and append it if the name
756							// isn't duplicated in the existing unit's dropins
757							for _, newDropin := range units[i].Dropins {
758								hasExistingDropin := false
759								for _, existingDropins := range outUnits[j].Dropins {
760									if existingDropins.Name == newDropin.Name {
761										hasExistingDropin = true
762										break
763									}
764								}
765								if !hasExistingDropin {
766									outUnits[j].Dropins = append(outUnits[j].Dropins, newDropin)
767								}
768							}
769							continue
770						}
771					}
772					klog.V(2).Infof("Found duplicate unit %v, appending dropin section", unitName)
773				}
774				continue
775			}
776			outUnits = append(outUnits, units[i])
777			unitNameMap[unitName] = true
778		}
779	
780		// Concat sshkey sections into the newest passwdUser in the list
781		// We make the assumption that there is only one user: core
782		// since that is the only supported user by design.
783		// It's technically possible, though, to have created another user
784		// during install time configs, since we only check the validity of
785		// the passwd section if it was changed. Explicitly error in that case.
786		if len(users) > 0 {
787			outUser := users[len(users)-1]
788			if outUser.Name != "core" {
