45	// GenerateReport generates a slice of mcfgv1.IrreconcilableChangeDiff based on the install-time parameters
46	// defined in the files stored in irreconcilableDifferencesReportGeneratorImpl.installTimeParamsPaths and the
47	// provided mcfgv1.MachineConfig.
48	// This function retrieves the install-time parameters from disk, performs the conversion of both MachineConfigs
49	// to JSON and evaluate the differences of the non-reconcilable sections (sections managed by the MCD like files
50	// or systemd units are skipped) as a JSON diff.
51	// The function returns error if an issue finding the base MachineConfig or if a JSON conversion error happens.
52	func (i *irreconcilableDifferencesReportGeneratorImpl) GenerateReport(
53		targetMachineConfig *mcfgv1.MachineConfig,
54	) ([]mcfgv1.IrreconcilableChangeDiff, error) {
55		baseMc := i.fetchBaseInstallTimeMachineConfig()
56		if baseMc == nil {
57			return nil, errors.New("cannot locate and read the install-time configuration")
58		}
59		baseNode, err := getJSONNodeFromMC(baseMc)
60		if err != nil {
61			return nil, fmt.Errorf("failed to get the install-time configuration JsonNode: %w", err)
62		}
63		targetNode, err := getJSONNodeFromMC(targetMachineConfig)
64		if err != nil {
65			return nil, fmt.Errorf("failed to get the target configuration JsonNode: %w", err)
66		}
67	
68		diff := baseNode.Diff(targetNode)
69		if len(diff) == 0 {
70			// No differences, ensure we report no differences
71			return nil, nil
72		}
73	
74		return createReport(diff), nil
75	}
