91	// getPathStringFromJSONPath stringifies a given jd.Path into jsonpath like notation.
92	// The notation is not RFC compliant, and it is a simplistic approach that just joins
93	// objects by dots and arrays indexes by square brackets and the array index.
94	func getPathStringFromJSONPath(path *jd.Path) string {
95		builder := &strings.Builder{}
96		for _, e := range *path {
97			switch e := e.(type) {
98			case jd.PathKey:
99				builder.WriteString("." + string(e))
100			case jd.PathIndex:
101				builder.WriteString("[" + strconv.Itoa(int(e)) + "]")
102			case jd.PathSet:
103			case jd.PathMultiset:
104			case jd.PathSetKeys:
105			case jd.PathMultisetKeys:
106			default:
107				// Don't care about the rest of cases for path simple string representation
108			}
109		}
110		return strings.TrimLeft(builder.String(), ".[]")
111	}
